import{_ as t,c as i,a,o as r}from"./app-CEcM0piI.js";const s={};function l(n,e){return r(),i("div",null,e[0]||(e[0]=[a('<p>单元测试:</p><ul><li>单元测试是针对最小的功能单元编写测试代码</li><li>Java程序最小的功能单元是方法</li><li>单元测试就是针对单个Java方法的测试</li></ul><p><strong>JUnit的设计:</strong></p><ul><li>TestCase：一个TestCase表示一个测试</li><li>TestSuite：一个TestSuite包含一组TestCase，表示一组测试</li><li>TestFixture：一个TestFixture表示一个测试环境</li><li>TestResult：用于收集测试结果</li><li>TestRunner：用于运行测试</li><li>TestListener：用于监听测试过程，收集测试数据</li><li>Assert：用于断言测试结果是否正确</li></ul><h3 id="beforeeach和aftereach注解" tabindex="-1"><a class="header-anchor" href="#beforeeach和aftereach注解"><span>@BeforeEach和AfterEach注解</span></a></h3><p><code>@BeforeEach</code> 和 <code>@AfterEach</code> 注解用于标记方法，这些方法会在每个测试方法执行前后自动调用。</p><ul><li><strong>@BeforeAll</strong>： 在所有测试方法执行之前仅运行一次。 常用于一次性初始化资源，这些资源在整个测试类中都会被多个测试方法共享。 需要注意的是，<code>@BeforeAll</code> 方法必须是静态的（static）。</li><li><strong>@AfterAll</strong>： 在所有测试方法执行之后仅运行一次。 常用于一次性清理资源，确保测试类执行完毕后资源被正确释放。 同样，<code>@AfterAll</code> 方法也必须是静态的（static）。</li><li><strong>@BeforeEach</strong>： 在每个测试方法执行之前运行。 常用于初始化每个测试方法所需的资源或设置测试环境。 确保每个测试方法都在一个干净的状态下开始。</li><li><strong>@AfterEach</strong>： 在每个测试方法执行之后运行。 常用于清理每个测试方法使用的资源或恢复测试环境。 确保每个测试方法都不会影响其他测试方法的执行。</li></ul><p>如果测试的方法与spring没有关系可以将spring的测试注解注释掉,这样在测试时就不会运行spring的环境可以更快速完成测试</p>',8)]))}const c=t(s,[["render",l]]),p=JSON.parse('{"path":"/back/junit/1/","title":"概述","lang":"zh-CN","frontmatter":{"title":"概述","createTime":"2025/06/18 20:59:22","permalink":"/back/junit/1/"},"readingTime":{"minutes":1.58,"words":473},"git":{"createdTime":1750599657000,"updatedTime":1750599657000,"contributors":[{"name":"pink","username":"pink","email":"pinkdopeybug@163.com","commits":1,"avatar":"https://avatars.githubusercontent.com/pink?v=4","url":"https://github.com/pink"}]},"filePathRelative":"notes/后端/JUnit/概述.md","headers":[]}');export{c as comp,p as data};
